# ── Import the mail gateway module ──────────────────────────────────────
def _search_email_history(query_name, query_email=None, password=None):
    """Search the real irconnect@usio.com mailbox (sent + received) for any
    thread involving this person — by name or email address. Returns a list
    of {date, subject, from, snippet} or raises on auth/connection failure.
    This queries the LIVE mailbox — no canned/demo results.
    Module-level so it's usable from both Mail Gateway and Market Intelligence
    (the 'track one analyst across all periods' model-retrieval feature)."""
    import imaplib, email as _eml
    from email.header import decode_header

    results = []
    m = imaplib.IMAP4_SSL("imap.secureserver.net", 993)
    m.login("irconnect@usio.com", password)

    for folder in ["INBOX", "Sent", "Sent Items", "INBOX.Sent"]:
        try:
            status, _ = m.select(folder, readonly=True)
            if status != "OK":
                continue
        except Exception:
            continue

        search_terms = []
        if query_email:
            search_terms.append(f'(OR FROM "{query_email}" TO "{query_email}")')
        if query_name:
            last_name = query_name.split()[-1]
            search_terms.append(f'(OR FROM "{last_name}" TO "{last_name}" SUBJECT "{last_name}")')

        for term in search_terms:
            try:
                _, data = m.search(None, term)
                ids = data[0].split()
                for eid in ids[-10:]:
                    _, msg_data = m.fetch(eid, "(RFC822)")
                    msg = _eml.message_from_bytes(msg_data[0][1])
                    subj_raw = decode_header(msg.get("Subject", ""))[0]
                    subj = subj_raw[0].decode(subj_raw[1] or "utf-8") if isinstance(subj_raw[0], bytes) else subj_raw[0]
                    results.append({
                        "date": msg.get("Date", "Unknown date"),
                        "subject": subj or "(no subject)",
                        "from": msg.get("From", "Unknown"),
                        "to": msg.get("To", "Unknown"),
                        "folder": folder,
                    })
            except Exception:
                continue

    m.logout()
    seen = set()
    unique = []
    for r in results:
        key = (r["subject"], r["date"])
        if key not in seen:
            seen.add(key)
            unique.append(r)
    return unique


