def robust_read_csv(path, **kwargs):
    """Read a CSV that may have been round-tripped through Excel. Excel can
    silently change encoding (UTF-8 -> Windows-1252/ANSI, or add a UTF-8 BOM)
    and, in some regional settings, even the delimiter (comma -> semicolon) —
    all while keeping the .csv extension, which is exactly what was breaking
    file uploads earlier. Tries standard UTF-8 first (the common, fast case),
    then falls back through other encodings, then a bounded set of known
    real-world delimiters — not open-ended auto-sniffing, which can guess a
    nonsensical separator out of a genuinely single-column file's own data.

    Also handles uploaded file objects (st.file_uploader), not just paths —
    those are streams, and reading one attempt consumes it, so every retry
    seeks back to the start first or it would silently see empty data.
    """
    _last_err = None
    _result = None
    _seekable = hasattr(path, "seek")
    for _enc in ("utf-8", "utf-8-sig", "cp1252", "latin1"):
        try:
            if _seekable:
                path.seek(0)
            _result = pd.read_csv(path, encoding=_enc, **kwargs)
            break
        except UnicodeDecodeError as e:
            _last_err = e
            continue
        except pd.errors.ParserError as e:
            _last_err = e
            break
    if _result is not None and len(_result.columns) > 1:
        if _seekable:
            path.seek(0)
        return _result
    # A successful parse yielding only one column is suspicious — likely the
    # wrong delimiter, not a genuinely single-column file. Try known
    # alternatives explicitly before trusting it.
    _best = _result
    for _enc in ("utf-8", "utf-8-sig", "cp1252", "latin1"):
        for _sep in (";", "\t", "|"):
            try:
                if _seekable:
                    path.seek(0)
                _alt = pd.read_csv(path, encoding=_enc, sep=_sep, **kwargs)
                if len(_alt.columns) > 1 and (_best is None or len(_alt.columns) > len(_best.columns)):
                    _best = _alt
            except Exception as e:
                _last_err = e
                continue
    if _seekable:
        path.seek(0)  # leave the stream at position 0 in case downstream code reads it again
    if _best is not None:
        return _best
    raise _last_err

