def save_institution_history(history: dict):
    import json as _json
    try:
        os.makedirs("outputs", exist_ok=True)
        with open(INSTITUTION_HISTORY_PATH, "w") as _f:
            _json.dump(history, _f, indent=2)
    except Exception:
        pass

def log_institution_snapshot(fund: str, snapshot: dict):
    """Append today's snapshot for a fund if it hasn't already been logged today.
    Safe to call every time the page renders — it's a no-op after the first
    call each calendar day per fund, so it won't spam the history file on
    every rerun."""
    today = datetime.now().strftime("%Y-%m-%d")
    history = load_institution_history()
    fund_log = history.setdefault(fund, [])
    if fund_log and fund_log[-1].get("date") == today:
        return  # already logged today
    fund_log.append({"date": today, **snapshot})
    save_institution_history(history)

def institution_trend(fund: str, field: str):
    """Compare the latest two logged snapshots for a field. Returns a plain-
    English trend string, or None if there's not yet enough history to say
    anything real — callers should show 'first data point' rather than guess."""
    history = load_institution_history().get(fund, [])
    if len(history) < 2:
        return None
    latest, prior = history[-1], history[-2]
    if field not in latest or field not in prior:
        return None
    try:
        _new, _old = float(latest[field]), float(prior[field])
    except (TypeError, ValueError):
        return None
    if _new == _old:
        return f"flat vs {prior['date']}"
    _dir = "up" if _new > _old else "down"
    return f"{_dir} from {int(_old) if _old==int(_old) else _old} on {prior['date']}"

