def mailto_link(to, subject, body="", label="✉️ Email", cc="", max_body_chars=1400):
    """Build a real, clickable mailto: link (opens the user's actual email client,
    pre-addressed and pre-filled). Bodies are capped — most mail clients truncate
    or fail on very long mailto URLs, so long content should stay in a copy/paste
    text_area alongside this as a fallback."""
    import urllib.parse as _up
    _body = body if len(body) <= max_body_chars else body[:max_body_chars] + "\n\n[…continued — see full text above]"
    _params = {"subject": subject, "body": _body}
    if cc:
        _params["cc"] = cc
    _qs = _up.urlencode(_params, quote_via=_up.quote)
    _href = f"mailto:{_up.quote(to)}?{_qs}"
    return (f"<a href='{_href}' style='display:inline-block;background:#2563EB;color:white;"
            f"padding:6px 14px;border-radius:6px;text-decoration:none;font-size:13px;font-weight:600;'>"
            f"{label}</a>")


