                            m=imaplib.IMAP4_SSL("imap.secureserver.net",993); m.login("irconnect@usio.com",ir_scan_pw)
                            m.select("INBOX"); _,d=m.search(None,"ALL"); ids=d[0].split()[-20:]
                            found=[]
                            for eid in reversed(ids):
                                _,md=m.fetch(eid,"(RFC822)"); msg=_emlmod.message_from_bytes(md[0][1])
                                subj=str(msg.get("Subject",""))
                                sender=msg.get("From","")
                                if any(kw in subj.lower() for kw in ["q2","quarter","results","numbers","final"]) and                                any(kw in sender.lower() for kw in ["mwhite","michael","cfo","usio"]):
                                    body=""
                                    if msg.is_multipart():
                                        for part in msg.walk():
                                            if part.get_content_type()=="text/plain":
                                                body=part.get_payload(decode=True).decode("utf-8","replace"); break
                                    else:
                                        body=msg.get_payload(decode=True).decode("utf-8","replace")
                                    found.append({"subj":subj,"body":body[:1500],"from":sender})
                            m.logout()
                            if found:
                                st.success(f"Found {len(found)} potential CFO email(s)")
                                for fe in found[:3]:
                                    with st.expander(f"📧 {fe['subj']}"):
                                        st.text(fe["body"])
                                        st.caption("Review and enter numbers in the Form tab above")
