        # Last correspondence — read directly from the meeting log file rather
        # than depending on get_fund_meetings(), which isn't defined until
        # further down this same tab's script order.
        def _last_correspondence(fund_name):
            _path = "models/meeting_log.csv"
            if not os.path.exists(_path):
                return None
            try:
                _log = robust_read_csv(_path)
                _matches = _log[_log["Fund"] == fund_name].sort_values("Date", ascending=False)
                return _matches.iloc[0] if not _matches.empty else None
            except Exception:
                return None

        def _institution_popover(_inst):
            _contact = CONTACT_REGISTRY.get(_inst["Fund"], {})
            _email = _contact.get("email", "")
            with st.popover(_inst["Fund"], use_container_width=True):
                st.markdown(f"**{_inst['Fund']}** — Score {_inst['Engagement_Score']}/100")
                st.caption(f"{_contact.get('name','Contact unknown')} — {_contact.get('title','—')}")
                _last = _last_correspondence(_inst["Fund"])
                if _last is not None:
                    st.markdown(f"**Last correspondence:** {_last['Date']} — {_last.get('Type','—')}")
                    st.caption(f"{_last.get('Notes','')}")
                    st.caption(f"Outcome: {_last.get('Outcome','—')}")
                else:
                    st.caption("No correspondence on file yet.")
                if _email:
                    st.markdown(
                        mailto_link(_email, f"USIO — Following up, {_inst['Fund']}", "Hi,\n\n",
                                    label=f"✉️ Email {_contact.get('name','Contact').split(',')[0].split(' —')[0]}"),
                        unsafe_allow_html=True
                    )
