        total       = len(INSTITUTIONS)
        hot_leads   = sum(1 for i in INSTITUTIONS if i["Engagement_Score"] >= 80)
        warm        = sum(1 for i in INSTITUTIONS if 40 <= i["Engagement_Score"] < 80)
        call_listeners_list = [i for i in INSTITUTIONS if i["Call_Listener"]]
        call_list   = len(call_listeners_list)
        non_holders_list = [i for i in INSTITUTIONS if not i["USIO_Holder"] and i["Engagement_Score"] >= 50]
        non_holders = len(non_holders_list)

        # Real "last updated" date — most recent institution history snapshot,
