        _history_all = load_institution_history()
        _all_snapshot_dates = [h[-1]["date"] for h in _history_all.values() if h]
        _last_updated = max(_all_snapshot_dates) if _all_snapshot_dates else datetime.now().strftime("%Y-%m-%d")

