        _listener_path = "data/q1_2026_call_listener_log.csv"
        _listener_upload = st.file_uploader("Upload Chorus Call listener CSV to replace the data below", type=["csv"], key="chorus_upload_live")
        if _listener_upload is not None:
            _upload_id = f"{_listener_upload.name}_{_listener_upload.size}"
            if st.session_state.get("_listener_upload_done") != _upload_id:
                os.makedirs("data", exist_ok=True)
                robust_read_csv(_listener_upload).to_csv(_listener_path, index=False)
                st.session_state["_listener_upload_done"] = _upload_id
                st.success("✅ Listener log updated — replacing the data shown below.")
                st.rerun()

        if os.path.exists(_listener_path):
            _listeners = robust_read_csv(_listener_path)
            _required_cols = {"Name","Firm","Title","Flag","Listen_Duration_Min","Pct_Listened","Date","Type"}
            if not _required_cols.issubset(_listeners.columns):
                st.warning(
                    f"This file is missing expected columns ({', '.join(sorted(_required_cols - set(_listeners.columns)))}) — "
                    f"showing the raw data below, but hot-lead flagging needs those columns to work."
                )
                st.dataframe(_listeners, use_container_width=True, hide_index=True)
                _hot = pd.DataFrame()
            else:
                _hot = _listeners[_listeners["Flag"].str.contains("HOT LEAD", na=False)]
            if not _hot.empty:
                for _, _h in _hot.iterrows():
                    st.markdown(
                        f"<div style='background:#3A2E15;border:1px solid #F0A830;border-radius:8px;padding:10px 14px;margin-bottom:8px;'>"
                        f"<b style='color:#F0A830;'>🔥 {_h['Name']}</b> — {_h['Title']}, {_h['Firm']}<br>"
                        f"<span style='font-size:12.5px;color:#E8D4A8;'>Listened {_h['Listen_Duration_Min']} min ({_h['Pct_Listened']}%) on {_h['Date']} — "
                        f"{_h['Type']}. Not yet covering, but a strong initiation candidate.</span>"
                        f"</div>", unsafe_allow_html=True
                    )
                    if st.button(f"➕ Add {_h['Name']} to New Analyst Onboarding Pipeline", key=f"add_onboard_{_h['Name']}"):
                        _onboard_path_early = "models/analyst_onboarding.csv"
                        _kit_items_early = [
                            "Business model summary sent", "Forensic positioning brief sent",
                            "Pre-built financial model sent", "Q&A cheat sheet sent",
                            "Catalyst calendar sent", "Earnings call replay link shared",
                            "1x1 call scheduled or completed", "Conference introduction made",
                        ]
                        os.makedirs("models", exist_ok=True)
                        if "onboarding" not in st.session_state:
                            try:
                                st.session_state.onboarding = robust_read_csv(_onboard_path_early).to_dict("records") if os.path.exists(_onboard_path_early) else []
                            except Exception:
                                st.session_state.onboarding = []
                        if not any(a.get("analyst_name")==_h["Name"] for a in st.session_state.onboarding):
                            st.session_state.onboarding.append({
                                "analyst_name": _h["Name"], "firm": _h["Firm"], "type": "Sell-Side",
                                "coverage_universe": "Fintech, Payments", "stage": "3 — Engaged",
                                "kit_sent_date": "", "last_contact": _h["Date"],
                                "notes": f"Sourced from Chorus Call listener log — {_h['Listen_Duration_Min']} min ({_h['Pct_Listened']}%) listened.",
                                "score": 78, "peer_holdings": "", "contact_email": "",
                                **{k: False for k in _kit_items_early},
                            })
                            pd.DataFrame(st.session_state.onboarding).to_csv(_onboard_path_early, index=False)
                            st.success(f"✅ Added to onboarding pipeline, Stage 3 — Engaged.")
                            st.rerun()
                        else:
                            st.caption("Already in the onboarding pipeline.")

            if _required_cols.issubset(_listeners.columns):
                with st.expander(f"📋 Full listener log — {len(_listeners)} attendees"):
                    st.dataframe(_listeners, use_container_width=True, hide_index=True)
        else:
            st.caption("No call listener log on file yet.")

        st.markdown("---")

        with st.expander(f"📋 NOBO Cross-Reference", expanded=False):
            st.markdown("#### 📋 NOBO Cross-Reference")
            st.caption("Request from Computershare quarterly — Excel or CSV with holder name, shares, address. Compares a list of names (the call listener log, a 13F pull, or your prospect queue) against USIO's actual NOBO shareholder file — matches are already-identified shareholders; everyone else is a real, unconfirmed prospect.")

            _nobo_path = "data/usio_nobo_list.csv"
            _nobo_upload = st.file_uploader("Upload NOBO list (CSV/Excel) to replace the data below", type=["csv","xlsx"], key="nobo_upload_live")
            if _nobo_upload is not None:
                _upload_id = f"{_nobo_upload.name}_{_nobo_upload.size}"
                if st.session_state.get("_nobo_upload_done") != _upload_id:
                    os.makedirs("data", exist_ok=True)
                    _new_nobo = robust_read_csv(_nobo_upload) if _nobo_upload.name.endswith(".csv") else pd.read_excel(_nobo_upload)
                    _new_nobo.to_csv(_nobo_path, index=False)
                    st.session_state["_nobo_upload_done"] = _upload_id
                    st.success("✅ NOBO list updated — replacing the data shown below.")
                    st.rerun()

            if os.path.exists(_nobo_path):
                _nobo_df = robust_read_csv(_nobo_path)
                if not {"Holder_Name","Shares"}.issubset(_nobo_df.columns):
                    st.warning("This file doesn't have the expected 'Holder_Name' and 'Shares' columns — showing raw data, but cross-referencing needs those column names to work.")
                    st.dataframe(_nobo_df, use_container_width=True, hide_index=True)
                else:
                    _compare_source = st.radio("Compare against:", ["Call Listener Log", "Coverage Network Prospect Queue", "IR Website Visitor Log"], horizontal=True, key="nobo_compare_src")

                    _visitor_path_early = "data/ir_website_visitor_log.csv"
                    if _compare_source == "Call Listener Log" and os.path.exists(_listener_path):
                        _compare_names = robust_read_csv(_listener_path)["Firm"].tolist()
                    elif _compare_source == "IR Website Visitor Log" and os.path.exists(_visitor_path_early):
                        _compare_names = robust_read_csv(_visitor_path_early)["Visitor_Organization"].tolist()
                    else:
                        _compare_names = [p.get("Fund","") for p in st.session_state.get("coverage_prospects", [])]

                    if not _compare_names:
                        st.caption("Nothing to compare yet — populate the Coverage Network Prospect Queue above first, or check the Call Listener Log.")
                    else:
                        def _nobo_match(name):
                            _n = str(name).lower()
                            for _, _row in _nobo_df.iterrows():
                                _h = str(_row["Holder_Name"]).lower()
                                if _n in _h or _h in _n:
                                    return _row["Holder_Name"], _row["Shares"]
                            return None, None

                        _matched, _unmatched = [], []
                        for _nm in _compare_names:
                            _match_name, _match_shares = _nobo_match(_nm)
                            if _match_name:
                                _matched.append((_nm, _match_name, _match_shares))
                            else:
                                _unmatched.append(_nm)

                        st.markdown(f"**{len(_matched)} identified on the NOBO file · {len(_unmatched)} not found — real prospects, not already-known shareholders**")
                        _out_col1, _out_col2 = st.columns(2)
                        with _out_col1:
                            if _matched:
                                st.markdown(
                                    "<div style='background:#173321;border:1px solid #22C55E;border-radius:8px;padding:10px 14px;'>"
                                    "<b style='color:#4ADE80;'>✅ Identified shareholders (already on the NOBO file)</b><br>"
                                    + "<br>".join(f"<span style='color:#E2E8F0;'>{_nm}</span> → <b>{_mn}</b> — {int(_sh):,} shares"
                                                 for _nm, _mn, _sh in _matched)
                                    + "</div>", unsafe_allow_html=True
                                )
                            else:
                                st.caption("None of the compared names matched the NOBO file.")
                        with _out_col2:
                            if _unmatched:
                                st.markdown(
                                    "<div style='background:#1E2D42;border:1px solid #475569;border-radius:8px;padding:10px 14px;'>"
                                    "<b style='color:#F1F5F9;'>🎯 Not on the NOBO file (genuine prospects)</b><br>"
                                    + "<span style='color:#94A3B8;'>" + ", ".join(_unmatched) + "</span>"
                                    + "</div>", unsafe_allow_html=True
                                )
                            else:
                                st.caption("Everything compared matched the NOBO file.")
            else:
                st.caption("No NOBO file on hand yet — request one from your transfer agent, or upload one above.")

            st.markdown("---")


            with st.expander("🌐 IR Website Visitor Log (Last 30 Days)", expanded=False):
                st.caption("Export from Google Analytics or Irwin/Q4 — CSV with institution, visits, pages viewed.")
                _visitor_path = "data/ir_website_visitor_log.csv"
                _visitor_upload = st.file_uploader("Upload IR visitor log CSV to replace the data below", type=["csv"], key="visitor_upload_live")
                if _visitor_upload is not None:
                    _upload_id = f"{_visitor_upload.name}_{_visitor_upload.size}"
                    if st.session_state.get("_visitor_upload_done") != _upload_id:
                        os.makedirs("data", exist_ok=True)
                        robust_read_csv(_visitor_upload).to_csv(_visitor_path, index=False)
                        st.session_state["_visitor_upload_done"] = _upload_id
                        st.success("✅ Visitor log updated — replacing the data shown below.")
                        st.rerun()

                if os.path.exists(_visitor_path):
                    _visitors = robust_read_csv(_visitor_path)
                    if "Category" not in _visitors.columns:
                        st.warning("This file doesn't have a 'Category' column (Call Attendee / Known Fund / New - Unidentified) — showing raw data without the new-visitor breakdown.")
                        st.dataframe(_visitors, use_container_width=True, hide_index=True)
                    else:
                        _new_visitors = _visitors[_visitors["Category"] == "New - Unidentified"]
                        _vcol1, _vcol2, _vcol3 = st.columns(3)
                        _vcol1.metric("Total visits", len(_visitors))
                        _vcol2.metric("Known / call attendees", len(_visitors) - len(_new_visitors))
                        _vcol3.metric("🆕 New / unidentified", len(_new_visitors))
                        if not _new_visitors.empty:
                            st.caption("These showed up on the site for the first time and aren't in any contact registry yet — worth a look before assuming they're not real interest.")

                        # ── Visit Engagement Score — simple, explainable, not a
                        #    hidden number: pages viewed matters more than raw
                        #    time (a long idle tab isn't real interest), so it's
                        #    weighted accordingly and capped at 100. ──────────
                        def _visit_score(pages, minutes):
                            try:
                                return min(100, round(float(pages) * 8 + float(minutes) * 3))
                            except Exception:
                                return 0
                        _visitors = _visitors.copy()
                        _visitors["_score"] = _visitors.apply(
                            lambda r: _visit_score(r.get("Pages_Viewed", 0), r.get("Time_On_Site_Min", 0)), axis=1)
                        _visitors = _visitors.sort_values("_score", ascending=False)

                        st.markdown(f"**Full visitor log — {len(_visitors)} visits**")
                        st.caption("Engagement score = (pages viewed × 8) + (minutes on site × 3), capped at 100 — pages weighted higher since a long idle tab isn't the same as active browsing. Sorted highest first.")

                        # Built with every HTML tag starting at column 0 — indenting
                        # HTML inside a triple-quoted f-string (matching the
                        # surrounding Python indentation) previously made Streamlit's
                        # markdown parser treat the indented lines as a code block
                        # under standard Markdown rules, which is what silently
                        # dropped the header row before.
                        _v_rows_html = ""
                        for _, _v in _visitors.iterrows():
                            _sc = int(_v["_score"])
                            _sc_color = "#4ADE80" if _sc >= 70 else ("#F0A830" if _sc >= 40 else "#94A3B8")
                            _v_rows_html += (
                                "<tr>"
                                f"<td>{_v.get('Visitor_Organization','—')}</td>"
                                f"<td>{_v.get('Category','—')}</td>"
                                f"<td style='text-align:center;'>{_v.get('Pages_Viewed','—')}</td>"
                                f"<td style='text-align:center;'>{_v.get('Time_On_Site_Min','—')}</td>"
                                f"<td style='white-space:nowrap;'>{_v.get('Date','—')}</td>"
                                f"<td style='text-align:center;color:{_sc_color};font-weight:700;'>{_sc}</td>"
                                f"<td style='text-align:left;'>{_v.get('Notes','')}</td>"
                                "</tr>"
                            )
                        _table_html = (
                            "<div style='max-height:420px;overflow-y:auto;border-radius:8px;'>"
                            "<table class='ir-table' style='width:100%;background:#1E293B;'>"
                            "<thead><tr>"
                            "<th>Visitor Organization</th><th>Category</th><th style='text-align:center;'>Pages Viewed</th>"
                            "<th style='text-align:center;'>Time on Site (min)</th><th>Date</th>"
                            "<th style='text-align:center;'>Score</th><th style='text-align:left;'>Notes</th>"
                            "</tr></thead>"
                            f"<tbody>{_v_rows_html}</tbody>"
                            "</table>"
                            "</div>"
                        )
                        st.markdown(_table_html, unsafe_allow_html=True)

                        # ── Select visitor(s) → add to the same Coverage Network
                        #    Prospect Queue used everywhere else, rather than
                        #    building a second, disconnected mailing list. ──────
                        st.markdown("**Select visitor(s) to add to the outreach queue:**")
                        _visitor_options = _visitors["Visitor_Organization"].tolist()
                        _selected_visitors = st.multiselect(
                            "Select visitor(s)", _visitor_options, key="visitor_log_select",
                            label_visibility="collapsed"
                        )
                        if st.button("➕ Add selected to Coverage Network Prospect Queue", key="add_visitors_to_queue",
                                     disabled=not _selected_visitors):
                            st.session_state.setdefault("coverage_prospects", [])
                            _existing_names = {p.get("Fund","").lower() for p in st.session_state.coverage_prospects}
                            _added = 0
                            for _name in _selected_visitors:
                                if _name.lower() not in _existing_names:
                                    _row = _visitors[_visitors["Visitor_Organization"] == _name].iloc[0]
                                    st.session_state.coverage_prospects.append({
                                        "Fund": _name, "Contact": "", "AUM": "", "Type": "Unknown",
                                        "Source Ticker": "", "Source": "IR Website Visitor Log",
                                        "Notes": f"Visit score {int(_row['_score'])} — {_row.get('Notes','')}",
                                        "Added": datetime.now().strftime("%Y-%m-%d"),
                                        "Status": "New — not yet contacted",
                                    })
                                    _added += 1
                            st.success(f"✅ Added {_added} visitor(s) to the prospect queue (see the Coverage Network section above).")
                            st.rerun()
                else:
                    st.caption("No visitor log on file yet.")

            st.markdown("---")

            # ── RETAIL INVESTOR COMMUNICATION PRIORITY ──────────────────────────────
            # Combines three real inputs — is this person an actual verified
            # shareholder (NOBO), have they been engaging on the site recently
            # (Visitor Log), and how urgent is what they actually asked (Inbound
            # Questions) — into one call-or-email recommendation per inquiry.
        with st.expander(f"📞 Retail Investor Communication Priority", expanded=False):
            st.markdown("#### 📞 Retail Investor Communication Priority")
            st.caption("Cross-references inbound IR questions against the NOBO file (verified shareholder?) and the Website Visitor Log (recently engaged?) to prioritize who gets a return call vs. a standard email reply.")

            _questions_path = "data/inbound_ir_questions.csv"
            _questions_upload = st.file_uploader("Upload inbound IR questions log (CSV) to replace the data below", type=["csv"], key="questions_upload_live")
            if _questions_upload is not None:
                _upload_id = f"{_questions_upload.name}_{_questions_upload.size}"
                if st.session_state.get("_questions_upload_done") != _upload_id:
                    os.makedirs("data", exist_ok=True)
                    robust_read_csv(_questions_upload).to_csv(_questions_path, index=False)
                    st.session_state["_questions_upload_done"] = _upload_id
                    st.success("✅ Inbound questions log updated.")
                    st.rerun()

            if not os.path.exists(_questions_path):
                st.caption("No inbound questions log on file yet — upload one above (columns: Name, Email, Date, Channel, Question_Summary, Urgency, Status).")
            else:
                _questions_df = robust_read_csv(_questions_path)
                _req_q_cols = {"Name","Email","Date","Channel","Question_Summary","Urgency","Status"}
                if not _req_q_cols.issubset(_questions_df.columns):
                    st.warning(f"Missing expected columns ({', '.join(sorted(_req_q_cols - set(_questions_df.columns)))}) — showing raw data only.")
                    st.dataframe(_questions_df, use_container_width=True, hide_index=True)
                else:
                    _nobo_df_for_q = robust_read_csv(_nobo_path) if os.path.exists(_nobo_path) else pd.DataFrame(columns=["Holder_Name","Shares"])
                    _visitors_for_q = robust_read_csv(_visitor_path) if os.path.exists(_visitor_path) else pd.DataFrame(columns=["Visitor_Organization"])

                    def _is_nobo_shareholder(name):
                        _n = str(name).lower()
                        for _, _row in _nobo_df_for_q.iterrows():
                            _h = str(_row["Holder_Name"]).lower()
                            if _n in _h or _h in _n:
                                return _row["Shares"]
                        return None

                    def _recently_visited(name):
                        _n = str(name).lower()
                        for _v in _visitors_for_q["Visitor_Organization"].astype(str):
                            if _n in _v.lower() or _v.lower() in _n:
                                return True
                        return False

                    _priority_rows = []
                    for _, _q in _questions_df[_questions_df["Status"] != "Responded"].iterrows():
                        _shares = _is_nobo_shareholder(_q["Name"])
                        _visited = _recently_visited(_q["Name"])
                        _urgency = str(_q["Urgency"])

                        if _shares is not None and _urgency == "High":
                            _action, _priority_score = "📞 Return call today — verified shareholder, high urgency", 3
                        elif _shares is not None and (_urgency == "Medium" or _visited):
                            _action, _priority_score = "📞 Return call this week — verified shareholder", 2
                        elif _shares is not None:
                            _action, _priority_score = "📧 Email response — verified shareholder, low urgency", 1
                        else:
                            _action, _priority_score = "📧 Standard email reply — not yet a verified shareholder", 0

                        _priority_rows.append({
                            "Name": _q["Name"], "Email": _q["Email"], "Date": _q["Date"], "Channel": _q["Channel"],
                            "Question": _q["Question_Summary"], "Urgency": _urgency,
                            "Verified Shareholder": f"{int(_shares):,} shares" if _shares is not None else "Not on NOBO file",
                            "Recent Site Visit": "Yes" if _visited else "No",
                            "Recommended Action": _action, "_sort": _priority_score,
                        })

                    _priority_df = pd.DataFrame(_priority_rows).sort_values("_sort", ascending=False).drop(columns=["_sort"])
                    _n_pending = len(_priority_df)
                    st.markdown(f"**{_n_pending} pending inquiries** ranked by priority")

                    for _, _r in _priority_df.iterrows():
                        _bg, _border = ("#173321", "#22C55E") if "Return call today" in _r["Recommended Action"] \
                            else ("#3A2E15", "#F0A830") if "Return call this week" in _r["Recommended Action"] \
                            else ("#1E2D42", "#475569")
                        st.markdown(
                            f"<div style='background:{_bg};border:1px solid {_border};border-radius:8px;padding:10px 14px;margin-bottom:8px;'>"
                            f"<div style='display:flex;justify-content:space-between;'>"
                            f"<b style='color:#F1F5F9;'>{_r['Name']}</b>"
                            f"<span style='color:#F1F5F9;font-weight:700;'>{_r['Recommended Action']}</span>"
                            f"</div>"
                            f"<div style='font-size:12px;color:#94A3B8;margin-top:3px;'>{_r['Channel']} · {_r['Date']} · Urgency: {_r['Urgency']} · "
                            f"{_r['Verified Shareholder']} · Recent site visit: {_r['Recent Site Visit']}</div>"
                            f"<div style='font-size:12.5px;color:#C8D8E8;margin-top:4px;'>\"{_r['Question']}\"</div>"
                            f"</div>", unsafe_allow_html=True
                        )
                        st.markdown(
                            mailto_link(_r["Email"], f"USIO Investor Relations — Following Up", "Hi,\n\nThank you for reaching out to Usio Investor Relations. ",
                                        label=f"✉️ Email {_r['Name'].split()[0]}"),
                            unsafe_allow_html=True
                        )

            st.markdown("---")

            # ── HOW TO FIND WHO OWNS FPAY / ANY COVERAGE STOCK ──────────────────────
        with st.expander(f"🔎 How to Pull 13F Holders for Any Coverage Stock", expanded=False):
            st.markdown("#### 🔎 How to Pull 13F Holders for Any Coverage Stock")
            st.caption("Free data, updated quarterly — this is how you build the prospect list from analyst coverage network targeting")

            focus_ticker = st.selectbox(
                "Select a coverage stock to find its 13F holders",
                options=[s["ticker"] for s in non_usio_coverage if s.get("relevance",0) >= 50],
                format_func=lambda t: next(
                    (f"{t} — {s['name']} (Relevance: {s.get('relevance',50)}/100)"
                     for s in analyst_data["coverage"] if s["ticker"]==t), t
                ),
                key="fpay_lookup_ticker_cfo"
            )

            focus_stock = next((s for s in analyst_data["coverage"] if s["ticker"]==focus_ticker), None)
            if focus_stock:
                rel   = focus_stock.get("relevance", 50)
                bridge= focus_stock.get("bridge","")

                col_how1, col_how2 = st.columns([1,1])

                with col_how1:
                    st.markdown(f"""
                <div style='border:0.5px solid #e0e0e0;border-radius:10px;padding:14px;background:var(--surface-2);height:100%'>
                  <div style='font-size:14px;font-weight:500;margin-bottom:8px'>
                    Why <b>{focus_ticker}</b> holders are USIO prospects
                  </div>
                  <div style='font-size:13px;color:#94A3B8;line-height:1.6;margin-bottom:10px'>{bridge}</div>
                  <div style='font-size:13px;background:{"#EAF3DE" if rel>=80 else "#FAEEDA" if rel>=60 else "#F1EFE8"};
                              color:{"#27500A" if rel>=80 else "#633806" if rel>=60 else "#888"};
                              padding:4px 10px;border-radius:6px;display:inline-block;font-weight:500'>
                    Prospect relevance: {rel}/100
                  </div>
                </div>
                """, unsafe_allow_html=True)

                with col_how2:
                    st.markdown(f"""
                <div style='border:0.5px solid #3B82F6;border-radius:10px;padding:14px;background:#1E2D45'>
                  <div style='font-size:13px;font-weight:500;color:#60A5FA;margin-bottom:10px'>
                    Step-by-step: Find who owns {focus_ticker}
                  </div>
                  <div style='font-size:12px;color:#93C5FD;line-height:2'>
                    <b>Step 1:</b> Use the
                    <a href='https://whalewisdom.com/stock/{focus_ticker.lower()}' target='_blank' style='color:#60A5FA'>WhaleWisdom</a>
                    or <a href='https://fintel.io/so/us/{focus_ticker.lower()}' target='_blank' style='color:#60A5FA'>Fintel</a>
                    link below — these are built specifically to answer "who holds this stock," which raw SEC EDGAR search isn't<br>
                    <b>Step 2:</b> Export the current institutional holder list for {focus_ticker}<br>
                    <b>Step 3:</b> Cross-reference against USIO's NOBO list<br>
                    <b>Step 4:</b> Remaining names = your outreach list<br>
                    <span style='color:#64748B;'>(SEC EDGAR's own full-text search only works well if you search by company
                    name, not ticker — it indexes filing prose, not a clean ownership table. Use it to double-check a specific
                    filing, not as the primary lookup.)</span>
                  </div>
                </div>
                """, unsafe_allow_html=True)

                st.markdown("<br>", unsafe_allow_html=True)

                # Quick links
                st.markdown("**Quick links to find holders of this stock:**")
                ql1, ql2, ql3, ql4 = st.columns(4)
                with ql1:
                    st.link_button(
                        f"📊 {focus_ticker} on WhaleWisdom",
                        f"https://whalewisdom.com/stock/{focus_ticker}",
                        use_container_width=True
                    )
                with ql2:
                    st.link_button(
                        f"📋 {focus_ticker} 13F on SEC (full-text)",
                        f"https://www.sec.gov/edgar/search/#/q=%22{focus_stock['name'].replace(' ','+')}%22&forms=13F-HR",
                        use_container_width=True,
                        help="Best-effort — 13F filings list the issuer's company name, not the ticker, so this searches by name. "
                             "It's still a full-text search over filing prose, not a real ownership index, so results can be sparse. "
                             "WhaleWisdom/Fintel/StockAnalysis (the other three buttons) are the reliable single-click lookups."
                    )
                with ql3:
                    st.link_button(
                        f"📈 {focus_ticker} holders — Fintel",
                        f"https://fintel.io/so/us/{focus_ticker.lower()}",
                        use_container_width=True
                    )
                with ql4:
                    st.link_button(
                        f"🔍 {focus_ticker} — StockAnalysis",
                        f"https://stockanalysis.com/stocks/{focus_ticker.lower()}/shareholders/",
                        use_container_width=True
                    )

                st.info(
                    f"💡 **Praxis Point workflow:** Pull {focus_ticker} institutional holders from WhaleWisdom or Fintel "
                    f"(both free, updated within days of 13F filing deadline) → export to CSV → "
                    f"upload to the NOBO gap analysis tool above → any fund on that list not on your NOBO = "
                    f"a pre-qualified prospect who trusts Scott Buck's research and understands the payments/fintech micro-cap thesis."
                )

                # ── FILE UPLOAD — the actually-reliable workflow. Clean data in Excel,
                #    upload the file, done. No copy-paste parsing to fight with. ──────
                if "coverage_prospects" not in st.session_state:
                    st.session_state.coverage_prospects = []

                # Known-holder check, defined once and used at the point of decision
                # (right here, on the parsed upload) rather than after the fact in a
                # second review table — a fund that already owns USIO should never
                # even reach the queue pre-checked as a "prospect."
                _known_holder_names = [i["Fund"] for i in INSTITUTIONS if i["USIO_Holder"]]
                def _matches_known_holder(name):
                    _n = str(name).lower()
                    for _h in _known_holder_names:
                        _h_l = _h.lower()
                        if _n in _h_l or _h_l in _n:
                            return _h
                        if _n.split()[0] == _h_l.split()[0] and len(_n.split()[0]) > 4:
                            return _h
                    return None

                st.markdown("---")
                st.markdown("##### 📂 Upload Cleaned Holder Data")
                st.caption(
                    f"Pull the {focus_ticker} holder table from WhaleWisdom/Fintel, clean it up in Excel "
                    f"(rename columns, drop what you don't need), and upload the file here — .xlsx or .csv."
                )

                _bundled_path = f"data/{focus_ticker.lower()}_13f_holders.csv"
                _has_bundled = os.path.exists(_bundled_path)

                _uploaded_file = st.file_uploader(
                    f"Upload {focus_ticker} holder file", type=["xlsx", "csv"],
                    key=f"holder_upload_{focus_ticker}", label_visibility="collapsed"
                )

                _holder_df = None
                _holder_source_label = ""
                if _uploaded_file is not None:
                    try:
                        _holder_df = (robust_read_csv(_uploaded_file) if _uploaded_file.name.endswith(".csv")
                                      else pd.read_excel(_uploaded_file))
                        _holder_df = _holder_df.drop(columns=[c for c in _holder_df.columns if str(c).startswith("Unnamed")])
                        _holder_source_label = f"Uploaded: {_uploaded_file.name}"
                    except Exception as _e:
                        st.error(f"Couldn't read that file: {_e}")
                elif _has_bundled:
                    _holder_df = robust_read_csv(_bundled_path)
                    _holder_source_label = f"Pre-loaded from Fintel (filing date {_holder_df['filing Date'].iloc[0] if 'filing Date' in _holder_df.columns else '—'})"

                if _holder_df is not None:
                    st.success(f"✅ {_holder_source_label} — {len(_holder_df)} institutions")

                    # Best-effort column mapping — works whether it's this exact Fintel
                    # export or a differently-labeled sheet from another source.
                    _cols = _holder_df.columns.tolist()
                    def _guess_col(*keywords):
                        for c in _cols:
                            if any(k in c.lower() for k in keywords):
                                return c
                        return None

                    _map_c1, _map_c2, _map_c3 = st.columns(3)
                    with _map_c1:
                        _inv_col = st.selectbox("Investor name column", _cols,
                            index=_cols.index(_guess_col("investor","fund","name")) if _guess_col("investor","fund","name") else 0,
                            key=f"map_inv_{focus_ticker}")
                    with _map_c2:
                        _shr_col_opts = ["(none)"] + _cols
                        _shr_guess = _guess_col("share")
                        _shr_col = st.selectbox("Shares held column", _shr_col_opts,
                            index=_shr_col_opts.index(_shr_guess) if _shr_guess else 0,
                            key=f"map_shr_{focus_ticker}")
                    with _map_c3:
                        _chg_col_opts = ["(none)"] + _cols
                        _chg_guess = _guess_col("% change","pct change","change %")
                        _chg_col = st.selectbox("% change column", _chg_col_opts,
                            index=_chg_col_opts.index(_chg_guess) if _chg_guess else 0,
                            key=f"map_chg_{focus_ticker}")

                    # Include column goes first — review happens right here, once,
                    # not again in a separate table after adding.
                    _preview_df = _holder_df.copy()
                    _preview_df.insert(0, "⚠️ Holder Match", _preview_df[_inv_col].apply(lambda n: _matches_known_holder(n) or ""))
                    _preview_df.insert(0, "Include", _preview_df["⚠️ Holder Match"].eq(""))

                    _n_flagged = int((_preview_df["⚠️ Holder Match"] != "").sum())
                    if _n_flagged:
                        st.warning(f"⚠️ {_n_flagged} rows look like existing USIO holders and are unchecked below — verify before including.")

                    _edited_preview = st.data_editor(
                        _preview_df,
                        use_container_width=True,
                        hide_index=True,
                        disabled=[c for c in _preview_df.columns if c != "Include"],
                        column_config={
                            "Include": st.column_config.CheckboxColumn("Include?", help="Uncheck to exclude — e.g. existing holders, wrong fund, not worth pursuing"),
                            "⚠️ Holder Match": st.column_config.TextColumn("⚠️ Holder Match", help="Auto-detected possible match to an existing USIO holder"),
                        },
                        key=f"file_preview_editor_{focus_ticker}",
                    )

                    # Surface the interesting moves — this is the actual demo narrative,
                    # not just a raw dump of 40 names.
                    if _chg_col != "(none)":
                        _movers = _holder_df.copy()
                        _movers["_chg_numeric"] = pd.to_numeric(_movers[_chg_col], errors="coerce")
                        _big_buys = _movers[_movers["_chg_numeric"] > 50].sort_values("_chg_numeric", ascending=False)
                        _big_sells = _movers[_movers["_chg_numeric"] < -50].sort_values("_chg_numeric")
                        if len(_big_buys) or len(_big_sells):
                            _mv1, _mv2 = st.columns(2)
                            with _mv1:
                                if len(_big_buys):
                                    st.markdown(f"**📈 Sharp increases (>50%)**")
                                    for _, _r in _big_buys.head(5).iterrows():
                                        st.caption(f"{_r[_inv_col]} — {_r['_chg_numeric']:+.0f}%")
                            with _mv2:
                                if len(_big_sells):
                                    st.markdown(f"**📉 Sharp decreases (<-50%)**")
                                    for _, _r in _big_sells.head(5).iterrows():
                                        st.caption(f"{_r[_inv_col]} — {_r['_chg_numeric']:+.0f}%")

                    _checked_count = int(_edited_preview["Include"].sum())
                    if st.button(f"➕ Add {_checked_count} checked rows to Prospect Queue", key=f"file_add_{focus_ticker}", type="primary"):
                        _added = 0
                        for _, _row in _edited_preview[_edited_preview["Include"]].iterrows():
                            _fund_name = str(_row[_inv_col]).strip()
                            if not _fund_name or _fund_name.lower() == "nan":
                                continue
                            st.session_state.coverage_prospects.append({
                                "Fund":          _fund_name,
                                "Contact":       "",
                                "AUM":           "",
                                "Type":          "Unknown",
                                "Source Ticker": focus_ticker,
                                "Source":        _holder_source_label,
                                f"{focus_ticker} Shares": _row[_shr_col] if _shr_col != "(none)" else "",
                                f"{focus_ticker} % Change": _row[_chg_col] if _chg_col != "(none)" else "",
                                "Added":         datetime.now().strftime("%Y-%m-%d"),
                                "Status":        "New — not yet contacted",
                            })
                            _added += 1
                        st.success(f"✅ Added {_added} funds to the prospect queue from {focus_ticker} research.")
                        st.rerun()

                with st.expander("📋 Or paste a table directly (less reliable — depends on the source site's HTML)"):
                    st.caption(
                        f"Some sites (WhaleWisdom in particular) render their tables as styled grids, not plain HTML "
                        f"tables — copy/paste from those often won't preserve columns cleanly. The file upload above is "
                        f"the reliable path; use this only if you don't want to open Excel first."
                    )
                    _bulk_paste = st.text_area(
                        "Paste table here", height=120,
                        placeholder="Paste tab-separated rows here...",
                        key=f"bulk_paste_{focus_ticker}", label_visibility="collapsed",
                    )
                    if _bulk_paste.strip():
                        import re as _re_bulk
                        _lines = [ln for ln in _bulk_paste.strip().split("\n") if ln.strip()]
                        _parsed_rows = []
                        for _ln in _lines:
                            _cells = _ln.split("\t") if "\t" in _ln else _re_bulk.split(r"\s{2,}", _ln.strip())
                            _cells = [c.strip() for c in _cells if c.strip() != ""]
                            if _cells:
                                _parsed_rows.append(_cells)
                        if _parsed_rows:
                            _max_cols = max(len(r) for r in _parsed_rows)
                            _padded = [r + [""] * (_max_cols - len(r)) for r in _parsed_rows]
                            _col_names = [f"Column {i+1}" for i in range(_max_cols)]
                            _raw_df = pd.DataFrame(_padded, columns=_col_names)
                            st.caption(f"Parsed {len(_raw_df)} rows — check this actually looks right before adding.")
                            _edited_df = st.data_editor(_raw_df, use_container_width=True, hide_index=True, key=f"bulk_edit_{focus_ticker}")
                            _fund_col = st.selectbox("Which column is the fund/investor name?", _col_names,
                                                      index=0, key=f"bulk_fundcol_{focus_ticker}")
                            if st.button(f"➕ Add all {len(_edited_df)} rows to Prospect Queue", key=f"bulk_add_{focus_ticker}"):
                                _added = 0
                                for _, _row in _edited_df.iterrows():
                                    _fund_name = str(_row[_fund_col]).strip()
                                    if not _fund_name or _fund_name.lower() in ("history","nan",""):
                                        continue
                                    _other = {c: _row[c] for c in _col_names if c != _fund_col and str(_row[c]).strip()}
                                    st.session_state.coverage_prospects.append({
                                        "Fund": _fund_name, "Contact": "", "AUM": "", "Type": "Unknown",
                                        "Source Ticker": focus_ticker, "Source": "Bulk paste",
                                        f"{focus_ticker} Shares": "",
                                        "Raw Data": " · ".join(f"{k}: {v}" for k, v in _other.items()),
                                        "Added": datetime.now().strftime("%Y-%m-%d"),
                                        "Status": "New — not yet contacted",
                                    })
                                    _added += 1
                                st.success(f"✅ Added {_added} funds to the prospect queue.")
                                st.rerun()

                # ── Manual single-row entry — fallback for a one-off addition/correction ──
                with st.expander("✍️ Add or correct a single prospect manually"):
                    with st.form(f"add_prospect_{focus_ticker}"):
                        cp1, cp2, cp3 = st.columns(3)
                        with cp1:
                            cp_fund    = st.text_input("Fund name")
                            cp_contact = st.text_input("Contact name (if known)")
                        with cp2:
                            cp_aum     = st.text_input("Approx AUM")
                            cp_shares  = st.number_input(f"{focus_ticker} shares held", min_value=0, step=1000)
                        with cp3:
                            cp_type    = st.selectbox("Fund type", ["Small-Cap Value","Micro-Cap Specialist",
                                                                    "Momentum Growth","Quant / Factor","Unknown"])
                            cp_source  = st.text_input("Source", value="WhaleWisdom 13F")
                        if st.form_submit_button(f"➕ Add to Prospect Queue from {focus_ticker} Research"):
                            if cp_fund:
                                st.session_state.coverage_prospects.append({
                                    "Fund":          cp_fund,
                                    "Contact":       cp_contact,
                                    "AUM":           cp_aum,
                                    "Type":          cp_type,
                                    "Source Ticker": focus_ticker,
                                    "Source":        cp_source,
                                    f"{focus_ticker} Shares": cp_shares,
                                    "Added":         datetime.now().strftime("%Y-%m-%d"),
                                    "Status":        "New — not yet contacted",
                                })
                                st.success(f"✅ {cp_fund} added to prospect queue from {focus_ticker} 13F research")
                                st.rerun()

                # Show prospect queue — review already happened once, at the point
                # each batch was added (the upload/paste tables above). This is
                # just the accumulated result, not a second place to re-decide.
                if st.session_state.coverage_prospects:
                    st.markdown(f"**Coverage network prospect queue — {len(st.session_state.coverage_prospects)} funds identified:**")

                    # Safety net only — catches anything added via paste/manual entry
                    # that skipped the upload table's built-in holder check.
                    _known_holder_names = [i["Fund"] for i in INSTITUTIONS if i["USIO_Holder"]]
                    def _queue_matches_holder(name):
                        _n = str(name).lower()
                        for _h in _known_holder_names:
                            _h_l = _h.lower()
                            if _n in _h_l or _h_l in _n or (_n.split()[0] == _h_l.split()[0] and len(_n.split()[0]) > 4):
                                return _h
                        return None
                    _slipped_through = [p["Fund"] for p in st.session_state.coverage_prospects if _queue_matches_holder(p.get("Fund",""))]
                    if _slipped_through:
                        st.warning(f"⚠️ These look like existing USIO holders — remove them below: {', '.join(_slipped_through)}")

                    df_cp = pd.DataFrame(st.session_state.coverage_prospects)
                    st.dataframe(df_cp, use_container_width=True, hide_index=True)

                    _rm_col, _clr_col = st.columns([2, 1])
                    with _rm_col:
                        _to_remove = st.selectbox("Remove a fund", ["—"] + [p["Fund"] for p in st.session_state.coverage_prospects], key="rm_prospect_pick")
                        if _to_remove != "—" and st.button("🗑️ Remove", key="rm_prospect_btn"):
                            st.session_state.coverage_prospects = [p for p in st.session_state.coverage_prospects if p["Fund"] != _to_remove]
                            st.rerun()
                    with _clr_col:
                        st.markdown("<div style='height:28px;'></div>", unsafe_allow_html=True)
                        if st.button("🗑️ Clear entire queue", key="clear_prospects"):
                            st.session_state.coverage_prospects = []
                            st.rerun()

                    csv_cp = df_cp.to_csv(index=False)
                    st.download_button(
                        "⬇️ Export prospect queue as CSV",
                        data=csv_cp,
                        file_name=f"USIO_coverage_network_prospects_{datetime.now().strftime('%Y%m%d')}.csv",
                        mime="text/csv",
                    )


            if selected_mode == "pre":
                st.markdown("#### 📋 Re-Rating Outreach Priority List — Pre-Q2 Earnings")
                st.caption("Ranked by engagement score · Focus on Aug 1-11 window before quiet period")
            else:
                st.markdown("#### 🚀 Post-Earnings Prospecting Priority List — 5-Day Window")
                st.caption("Ranked by prospect score · Days 1-3 = top 80+ scores · Days 3-5 = 40-79 scores · Day 5+ = NDR pipeline")

            # ── AUTOMATED PROSPECTING PIPELINE ──────────────────────────────────────
            st.markdown("---")
        st.markdown("## 📧 Closed-Loop Earnings Call Outreach")
        st.caption("Generate personalized pre-earnings emails · Review and approve before sending via IRConnect")

        # Call logistics — edit these each quarter
        CALL_LOGISTICS = {
            "date":        "Wednesday, August 12, 2026",
            "time":        "4:30 PM Eastern Time",
            "webcast_url": "https://usio.com/events/",
            "dial_in_us":  "1-844-883-3890",
            "dial_in_intl":"1-412-317-9246",
            "replay_code": "USIO Q2 2026",
            "replay_avail":"Available approximately 1 hour after the call through August 26, 2026",
            "from_name":   "Praxis Point IR on behalf of USIO",
            "from_email":  "irconnect@usio.com",
        }

        # Contact registry — maps fund to primary IR contact
        # CONTACT_REGISTRY now defined at global scope (top of file) so it can be
        # used from the institution cards above as well as this generator.

        def generate_email_draft(inst: dict, logistics: dict, contact: dict) -> dict:
            """Generate a fully personalized earnings call invitation email."""

            fund        = inst["Fund"]
            score       = inst["Engagement_Score"]
            is_holder   = inst["USIO_Holder"]
            peers       = inst["Peer_Holdings"]
            call_listen = inst["Call_Listener"]
            visits      = inst["IR_Visits_30d"]
            contact_name= contact["name"].split()[0] if contact["name"] != "IR Team" else "Team"

            # Tailor the thesis paragraph by buyer profile
            if inst["Type"] in ["Micro-Cap Specialist", "Small-Cap Value"]:
                thesis_hook = (
                    f"As a firm focused on small-cap value, we believe USIO represents "
                    f"a compelling re-rating opportunity ahead of our Q2 earnings. "
                    f"Three of our five covering analysts have inactive models — we expect "
                    f"re-initiations with upgraded FY2027 price targets following this print, "
                    f"creating a potential triple catalyst: EPS inflection, multiple expansion, "
                    f"and coverage resumption simultaneously."
                )
            elif inst["Type"] == "Momentum Growth":
                thesis_hook = (
                    f"USIO's Q1 2026 results marked a significant inflection — record revenues, "
                    f"break-even EPS beating consensus by 50%, and 28% growth in payment volumes processed. "
                    f"We believe the FY2027 setup is compelling for growth-oriented investors, "
                    f"with analyst upgrades likely to follow our Q2 print on August 12."
                )
            else:
                thesis_hook = (
                    f"USIO's Q2 2026 earnings on August 12 represents an important catalyst. "
                    f"With consensus analyst price targets at $5.12 vs our current price of $2.15 — "
                    f"138% implied upside — and three analysts expected to re-initiate coverage "
                    f"with updated FY2027 models post-earnings, we wanted to ensure you have "
                    f"direct access to management's prepared remarks and Q&A."
                )

            # Add peer reference if relevant
            peer_note = ""
            if peers and not is_holder:
                peer_str = " and ".join(peers[:2])
                peer_note = (
                    f"\n\nGiven your position in {peer_str}, we believe USIO's ACH processing "
                    f"and PayFac-in-a-Box platform offers a complementary exposure to the same "
                    f"payment infrastructure thesis at a significantly earlier stage of the growth curve."
                )

            # Personalization hook based on engagement signals
            if call_listen and visits >= 3:
                engagement_note = (
                    f"\n\nWe noticed strong interest from your team — thank you for your attention "
                    f"to USIO's Q1 replay and recent IR materials. We would welcome a brief call "
                    f"with our CFO or IR team ahead of earnings if that would be helpful."
                )
            elif call_listen:
                engagement_note = (
                    f"\n\nThank you for listening to our Q1 earnings call. We hope the replay "
                    f"provided useful context on our growth trajectory. We'd welcome any questions "
                    f"ahead of the Q2 print."
                )
            elif visits >= 2:
                engagement_note = (
                    f"\n\nWe appreciate your interest in USIO's investor relations materials. "
                    f"Please don't hesitate to reach out directly if you'd like to speak with "
                    f"management ahead of earnings."
                )
            else:
                engagement_note = (
                    f"\n\nWe would welcome the opportunity to speak with your team ahead of earnings "
                    f"to provide context on our growth strategy and FY2027 outlook."
                )

            subject = (
                f"USIO Q2 2026 Earnings Call — August 12, 2026 at 4:30 PM ET"
                + (" | Re-Rating Catalyst" if score >= 80 and not is_holder else "")
            )

            body = f"""Dear {contact_name},

        {thesis_hook}{peer_note}{engagement_note}

        We cordially invite you to join USIO, Inc.'s Second Quarter 2026 Earnings Conference Call:

          Date:     {logistics["date"]}
          Time:     {logistics["time"]}
          Webcast:  {logistics["webcast_url"]}

          Dial-In (US):           {logistics["dial_in_us"]}
          Dial-In (International):{logistics["dial_in_intl"]}

        A replay will be available approximately one hour after the call through {logistics["replay_avail"].split("through")[1].strip() if "through" in logistics["replay_avail"] else "August 26, 2026"}.

        Management will provide prepared remarks covering Q2 financial results and an update on our FY2026 guidance of 10-12% revenue growth and continued positive adjusted EBITDA. A Q&A session will follow.

        If you would like to schedule a one-on-one with our CFO or IR team ahead of the call, please reply to this email or contact us at {logistics["from_email"]}.

        Best regards,

        {logistics["from_name"]}
        {logistics["from_email"]}

        ---
        Usio, Inc. (NASDAQ: USIO) | San Antonio, TX
        This message is intended for institutional investors and financial professionals only.
        """
            return {"subject": subject, "body": body, "to_email": contact["email"], "to_name": contact["name"]}

        # ── DRAFT GENERATOR UI ──────────────────────────────────────────────────

        # Initialize session state for draft management
        if "email_drafts"    not in st.session_state: st.session_state.email_drafts    = {}
        if "email_sent"      not in st.session_state: st.session_state.email_sent      = set()
        if "email_approved"  not in st.session_state: st.session_state.email_approved  = set()

        # Score threshold selector
        col_thresh, col_info = st.columns([1, 2])
        with col_thresh:
            send_threshold = st.selectbox(
                "Generate drafts for institutions scoring above:",
                [90, 80, 70, 50],
                format_func=lambda x: f"Score {x}+ ({sum(1 for i in INSTITUTIONS if i['Engagement_Score']>=x)} institutions)"
            )
        with col_info:
            st.markdown("<br>", unsafe_allow_html=True)
            eligible = [i for i in INSTITUTIONS if i["Engagement_Score"] >= send_threshold]
            st.info(f"**{len(eligible)} institutions** will receive personalized call invitations · Sent from `irconnect@usio.com`")

        if st.button("✉️ Generate All Personalized Drafts", type="primary", use_container_width=False):
            for inst in eligible:
                contact = CONTACT_REGISTRY.get(inst["Fund"], {
                    "name": "Investment Team", "email": "ir@" + inst["Fund"].lower().replace(" ","") + ".com", "title": "Portfolio Relations"
                })
                draft = generate_email_draft(inst, CALL_LOGISTICS, contact)
                st.session_state.email_drafts[inst["Fund"]] = {
                    "draft":   draft,
                    "inst":    inst,
                    "contact": contact,
                }
            st.success(f"✅ {len(eligible)} personalized drafts generated — review each below before approving")
            st.rerun()

        # ── DISPLAY DRAFTS FOR REVIEW ────────────────────────────────────────────
        if st.session_state.email_drafts:
            st.markdown(f"### 📋 Draft Review Queue — {len(st.session_state.email_drafts)} emails")
            st.caption("Review each draft · Edit subject/body if needed · Click Approve & Send when ready")

            for fund, item in st.session_state.email_drafts.items():
                draft   = item["draft"]
                inst    = item["inst"]
                contact = item["contact"]
                score   = inst["Engagement_Score"]
                sent    = fund in st.session_state.email_sent
                approved= fund in st.session_state.email_approved

                if score >= 80:   border_color = "#27500A"
                elif score >= 50: border_color = "#854F0B"
                else:             border_color = "#888888"

                with st.expander(
                    f"{'✅ SENT' if sent else '✓ APPROVED' if approved else '📝 DRAFT'} — "
                    f"{fund} · Score: {score} · To: {contact['name']} <{draft['to_email']}>",
                    expanded=not sent
                ):
                    col_meta, col_score = st.columns([4, 1])

                    with col_meta:
                        # Editable subject
                        edited_subject = st.text_input(
                            "Subject line", value=draft["subject"],
                            key=f"subj_{fund}"
                        )
                        # Editable body
                        edited_body = st.text_area(
                            "Email body (edit before approving)",
                            value=draft["body"],
                            height=320,
                            key=f"body_{fund}"
                        )

                        # Personalization signals shown as context
                        st.markdown(f"""
                        <div style='font-size:13px;color:#94A3B8;margin-top:6px'>
                          <b>Personalization signals used:</b>
                          {'✅ Q1 call listener (' + inst['Listen_Duration'] + ')' if inst['Call_Listener'] else '⭕ Did not listen to Q1 call'} ·
                          {inst['IR_Visits_30d']} IR site visits (30d) ·
                          Peers: {", ".join(inst["Peer_Holdings"]) if inst["Peer_Holdings"] else "none"} ·
                          {'✅ Current holder (' + f"{inst['Shares']:,} shares)" if inst['USIO_Holder'] else '⭕ Not a current holder'}
                        </div>
                        """, unsafe_allow_html=True)

                    with col_score:
                        st.markdown(f"""
                        <div style='text-align:center;padding:10px;border-radius:8px;
                                    background:{"#EAF3DE" if score>=80 else "#FAEEDA"};
                                    border:0.5px solid {border_color}'>
                          <div style='font-size:9px;color:{border_color};font-weight:500'>Engagement</div>
                          <div style='font-size:26px;font-weight:700;color:{border_color}'>{score}</div>
                          <div style='font-size:8px;color:{border_color}'>/ 100</div>
                        </div>
                        """, unsafe_allow_html=True)

                    st.markdown("---")

                    if sent:
                        st.success(f"✅ Email sent to {contact['name']} at {draft['to_email']}")

                    elif approved:
                        col_send, col_cancel = st.columns([1, 1])
                        with col_send:
                            if st.button(f"📤 Send Now to {draft['to_email']}", key=f"send_{fund}", type="primary"):
                                # Send via SMTP through IRConnect
                                import smtplib
                                from email.mime.text import MIMEText
                                from email.mime.multipart import MIMEMultipart
                                import os

                                ir_password = os.getenv("IR_PASSWORD", "")
                                if not ir_password:
                                    st.error("IR_PASSWORD not set in environment. Add it to your .env file.")
                                else:
                                    try:
                                        msg = MIMEMultipart()
                                        msg["From"]    = f"USIO Investor Relations <{CALL_LOGISTICS['from_email']}>"
                                        msg["To"]      = draft["to_email"]
                                        msg["Subject"] = st.session_state[f"subj_{fund}"]
                                        msg.attach(MIMEText(st.session_state[f"body_{fund}"], "plain"))

                                        with smtplib.SMTP_SSL("smtpout.secureserver.net", 465) as smtp:
                                            smtp.login(CALL_LOGISTICS["from_email"], ir_password)
                                            smtp.sendmail(CALL_LOGISTICS["from_email"], draft["to_email"], msg.as_string())

                                        st.session_state.email_sent.add(fund)
                                        st.success(f"✅ Sent to {contact['name']} at {draft['to_email']}")
                                        st.rerun()
                                    except Exception as e:
                                        st.error(f"Send failed: {str(e)}")
                        with col_cancel:
                            if st.button("↩ Back to Draft", key=f"unapprove_{fund}"):
                                st.session_state.email_approved.discard(fund)
                                st.rerun()

                    else:
                        col_approve, col_discard = st.columns([1, 1])
                        with col_approve:
                            if st.button(f"✓ Approve for Sending", key=f"approve_{fund}", type="primary"):
                                st.session_state.email_approved.add(fund)
                                st.rerun()
                        with col_discard:
                            if st.button("🗑 Remove from queue", key=f"discard_{fund}"):
                                del st.session_state.email_drafts[fund]
                                st.rerun()

            # ── SEND SUMMARY ────────────────────────────────────────────────────
            if st.session_state.email_sent:
                st.markdown("---")
                st.markdown("### 📊 Outreach Send Log")
                for fund in st.session_state.email_sent:
                    item    = st.session_state.email_drafts.get(fund, {})
                    contact = item.get("contact", {})
                    score   = item.get("inst", {}).get("Engagement_Score", "—")
                    st.success(f"✅ **{fund}** → {contact.get('name','—')} · Score: {score} · Sent {datetime.now().strftime('%b %d %Y %H:%M')}")

                st.caption(f"Post-send action: Monitor Chorus Call replay data after Aug 12 to see who dialed in from your outreach list. Upload listener CSV to the Data Sources section above to close the loop.")

                st.caption(f"Post-send action: Monitor Chorus Call replay data after Aug 12 to see who dialed in from your outreach list. Upload listener CSV to the Data Sources section above to close the loop.")

        # ═══════════════════════════════════════════════════════════════════════
        # NEW ANALYST ONBOARDING TRACKER
        # ═══════════════════════════════════════════════════════════════════════
        st.markdown("---")
        st.markdown("## 🎓 New Analyst Onboarding Tracker")
        st.caption(
            "Track every new sell-side and buy-side analyst from first contact through model-built and conviction. "
            "The goal: get them from cold → thesis-understood in 90 minutes, then from understood → evangelist."
        )

        ONBOARD_PATH = "models/analyst_onboarding.csv"
        os.makedirs("models", exist_ok=True)

        # Onboarding stages with colors and definitions
        ONBOARD_STAGES = {
            "1 — Cold":          {"color":"#9E9E9E","def":"Aware of ticker, no thesis understanding"},
            "2 — Kit Sent":      {"color":"#2196F3","def":"Received onboarding kit, reading guide sent"},
            "3 — Engaged":       {"color":"#FF9800","def":"Opened model request, attended call, or replied"},
            "4 — Thesis Understood":{"color":"#9C27B0","def":"Asked good Q&A questions, understands PayFac/ACH thesis"},
            "5 — Model Built":   {"color":"#00897B","def":"Has working financial model, covering formally or informally"},
            "6 — Evangelist":    {"color":"#375623","def":"Actively recommending to PM or published note"},
        }

        KIT_ITEMS = [
            "Business model summary sent",
            "Forensic positioning brief sent",
            "Pre-built financial model sent",
            "Q&A cheat sheet sent",
            "Catalyst calendar sent",
            "Earnings call replay link shared",
            "1x1 call scheduled or completed",
            "Conference introduction made",
        ]

        if not os.path.exists(ONBOARD_PATH):
            _seed_onboarding = pd.DataFrame([{
                "analyst_name": "Mike Grondahl",
                "firm": "Northland Securities",
                "type": "Sell-Side",
                "coverage_universe": "Fintech, Payments, Financial Technology",
                "stage": "3 — Engaged",
                "kit_sent_date": "",
                "last_contact": "2026-05-14",
                "notes": ("Attended the full Q1 2026 earnings call (58 min, 100% listened) — sourced from the Chorus Call "
                          "listener log. Non-covering, but Head of Equities/Director of Research at Northland, and covers "
                          "USIO's direct peer set (EEFT, GDOT, MGI) — a strong initiation candidate, not a cold outreach. "
                          "🔥 Hot lead — prioritize the kit + 1x1 outreach."),
                "score": 78,
                "peer_holdings": "EEFT, GDOT, MGI",
                "contact_email": "mgrondahl@northlandsecurities.com",  # unconfirmed — verify before outreach
            }] + [{k: "" for k in [
                "analyst_name","firm","type","coverage_universe","stage","kit_sent_date",
                "last_contact","notes","score","peer_holdings","contact_email"
            ]} for _ in range(0)])
            for _item in KIT_ITEMS:
                _seed_onboarding[_item] = False
            _seed_onboarding.to_csv(ONBOARD_PATH, index=False)

        if "onboarding" not in st.session_state:
            try:
                st.session_state.onboarding = robust_read_csv(ONBOARD_PATH).to_dict("records")
            except:
                st.session_state.onboarding = []

        # ── PIPELINE VIEW ──────────────────────────────────────────────────────
        st.markdown("#### Pipeline View — Analysts by Stage")

        stage_cols = st.columns(len(ONBOARD_STAGES))
        for col, (stage, meta) in zip(stage_cols, ONBOARD_STAGES.items()):
            analysts_in_stage = [a for a in st.session_state.onboarding if a.get("stage")==stage]
            with col:
                st.markdown(
                    f"<div style='background:{meta['color']};border-radius:8px;padding:8px 6px;"
                    f"text-align:center;color:white;margin-bottom:8px'>"
                    f"<div style='font-size:13px;font-weight:600'>{stage}</div>"
                    f"<div style='font-size:22px;font-weight:700'>{len(analysts_in_stage)}</div>"
                    f"<div style='font-size:12px;opacity:0.85'>{meta['def'][:35]}...</div>"
                    f"</div>",
                    unsafe_allow_html=True
                )
                for a in analysts_in_stage:
                    _is_hot = a.get("score", 0) and float(a.get("score", 0)) >= 70
                    st.markdown(
                        f"<div style='background:#1E2D42;border:1px solid {meta['color']};"
                        f"border-radius:6px;padding:5px 8px;margin-bottom:4px;font-size:13px'>"
                        f"<b style='color:#F1F5F9;'>{'🔥 ' if _is_hot else ''}{a.get('analyst_name','—')}</b>"
                        f"{' <span style=\"color:#F0A830;font-size:11px;font-weight:700;\">HOT LEAD</span>' if _is_hot else ''}<br>"
                        f"<span style='color:#94A3B8'>{a.get('firm','—')} · {a.get('type','—')}</span>"
                        f"</div>",
                        unsafe_allow_html=True
                    )

        st.markdown("---")

        # ── ADD / EDIT ANALYST ──────────────────────────────────────────────────
        ob_tab1, ob_tab2, ob_tab3 = st.tabs([
            "➕ Add New Analyst",
            "📋 All Analysts — Progress View",
            "📊 Onboarding Analytics"
        ])

        with ob_tab1:
            st.markdown("**Add a new analyst to the onboarding pipeline:**")
            with st.form("add_analyst_form"):
                oc1, oc2, oc3 = st.columns(3)
                with oc1:
                    ob_name    = st.text_input("Analyst name*")
                    ob_firm    = st.text_input("Firm*")
                    ob_type    = st.selectbox("Type", ["Buy-Side","Sell-Side","Independent"])
                    ob_stage   = st.selectbox("Current stage", list(ONBOARD_STAGES.keys()))
                with oc2:
                    ob_email   = st.text_input("Email")
                    ob_peers   = st.text_input("Peer holdings (comma-sep)", placeholder="GDOT, PRTH, RPAY")
                    ob_universe= st.text_input("Coverage universe", placeholder="Fintech, Payments, Small-cap")
                    ob_score   = st.slider("Engagement score (0-100)", 0, 100, 30)
                with oc3:
                    st.markdown("**Kit items sent:**")
                    kit_sent = {}
                    for item in KIT_ITEMS:
                        kit_sent[item] = st.checkbox(item, key=f"kit_{item[:20]}")

                ob_notes = st.text_area("Notes / how they were sourced", height=80)

                if st.form_submit_button("➕ Add to Pipeline", type="primary"):
                    if ob_name and ob_firm:
                        new_entry = {
                            "analyst_name": ob_name,
                            "firm":         ob_firm,
                            "type":         ob_type,
                            "coverage_universe": ob_universe,
                            "stage":        ob_stage,
                            "kit_sent_date": datetime.now().strftime("%Y-%m-%d") if any(kit_sent.values()) else "",
                            "last_contact": datetime.now().strftime("%Y-%m-%d"),
                            "notes":        ob_notes,
                            "score":        ob_score,
                            "peer_holdings":ob_peers,
                            "contact_email":ob_email,
                            **kit_sent
                        }
                        st.session_state.onboarding.append(new_entry)
                        pd.DataFrame(st.session_state.onboarding).to_csv(ONBOARD_PATH, index=False)
                        st.success(f"✅ {ob_name} ({ob_firm}) added to Stage: {ob_stage}")
                        st.rerun()
                    else:
                        st.warning("Analyst name and firm are required.")

            # Pre-load known targets
            st.markdown("---")
            st.markdown("**Quick-add known priority targets:**")
            PRIORITY_TARGETS = [
                {"analyst_name":"Michael Diana","firm":"Maxim Group","type":"Sell-Side",
                 "stage":"3 — Engaged","score":70,"peer_holdings":"USIO, payments",
                 "contact_email":"mdiana@maxim.com",
                 "notes":"Attended Q1 2026 call. Asked questions. Model request sent Aug 1 deadline."},
                {"analyst_name":"Barry Sine","firm":"Litchfield Hills Research","type":"Sell-Side",
                 "stage":"3 — Engaged","score":75,"peer_holdings":"USIO, GDOT",
                 "contact_email":"bsine@litchfieldhills.com",
                 "notes":"Attended Q1 2026 call. Best questions on PayFac/Usio One. No PT published."},
                {"analyst_name":"Gary Prestopino","firm":"Barrington Research","type":"Sell-Side",
                 "stage":"2 — Kit Sent","score":60,"peer_holdings":"USIO, PRTH, GDOT",
                 "contact_email":"gprestopino@barrington.com",
                 "notes":"Meeting scheduled Aug 1. Last active with $4.00 PT. Re-initiation expected post-Q2."},
            ]
            existing_names = [a.get("analyst_name") for a in st.session_state.onboarding]

            qcols = st.columns(len(PRIORITY_TARGETS))
            for col, target in zip(qcols, PRIORITY_TARGETS):
                with col:
                    already = target["analyst_name"] in existing_names
                    st.markdown(
                        f"<div style='background:{'#EAF3DE' if already else '#E3F2FD'};"
                        f"border-radius:8px;padding:10px;margin-bottom:8px'>"
                        f"<b>{target['analyst_name']}</b><br>"
                        f"<span style='font-size:12px;color:#94A3B8'>{target['firm']}</span><br>"
                        f"<span style='font-size:13px;color:#60A5FA'>{target['stage']}</span>"
                        f"</div>",
                        unsafe_allow_html=True
                    )
                    if already:
                        st.caption("✅ Already in pipeline")
                    else:
                        if st.button(f"Add {target['analyst_name'].split()[0]}", key=f"qa_{target['analyst_name']}"):
                            target["kit_sent_date"] = datetime.now().strftime("%Y-%m-%d")
                            target["last_contact"]  = datetime.now().strftime("%Y-%m-%d")
                            for item in KIT_ITEMS:
                                target[item] = False
                            st.session_state.onboarding.append(target)
                            pd.DataFrame(st.session_state.onboarding).to_csv(ONBOARD_PATH, index=False)
                            st.success(f"Added {target['analyst_name']}")
                            st.rerun()

        with ob_tab2:
            st.markdown("**All analysts — progress tracking and stage updates:**")
            if not st.session_state.onboarding:
                st.info("No analysts in pipeline yet. Add one using the form above.")
            else:
                for i, analyst in enumerate(st.session_state.onboarding):
                    stage     = analyst.get("stage","1 — Cold")
                    stage_clr = ONBOARD_STAGES.get(stage,{}).get("color","#9E9E9E")
                    kit_count = sum(1 for item in KIT_ITEMS if analyst.get(item))
                    kit_pct   = int(kit_count/len(KIT_ITEMS)*100)

                    with st.expander(
                        f"{'🟢' if kit_pct==100 else '🟡' if kit_pct>=50 else '🔴'} "
                        f"**{analyst.get('analyst_name','—')}** — {analyst.get('firm','—')} "
                        f"· {stage} · Kit: {kit_pct}%"
                    ):
                        col_d1, col_d2, col_d3 = st.columns([2,2,2])
                        with col_d1:
                            st.markdown(f"**Type:** {analyst.get('type','—')}")
