        # Build city/region lookup
        def get_institutions_for_location(location, ndr_type="in_person"):
            if ndr_type == "virtual":
                # Virtual: show all non-holders with score >= 40, sorted by score
                candidates = [i for i in INST_DB if not i["usio_holder"] and i["score"] >= 40]
            else:
                # In-person: filter by city/region
                city_map = {
                    "New York":      ["New York"],
                    "Boston":        ["Boston"],
                    "San Francisco": ["San Francisco","San Jose"],
                    "Chicago":       ["Chicago","Milwaukee"],
                    "Minneapolis / Midwest": ["Minneapolis","Milwaukee","Chicago"],
                    "Texas / Denver": ["Texas / Denver","Dallas","Austin","Houston","Denver"],
                    "Philadelphia / Baltimore": ["Philadelphia / Baltimore","Philadelphia","Baltimore"],
                }
                target_cities = city_map.get(location, [location])
                candidates = [i for i in INST_DB if i["city"] in target_cities]
            # Sort: non-holders first by score, then holders by score
            non_holders = sorted([i for i in candidates if not i["usio_holder"]], key=lambda x: -x["score"])
            holders     = sorted([i for i in candidates if i["usio_holder"]],     key=lambda x: -x["score"])
            return non_holders + holders

