        q3.metric("Buy-side",             sum(1 for m in upcoming if m["Side"]=="Buy-side"),  delta="institutions")
        q4.metric("This week",            sum(1 for m in upcoming if (datetime.strptime(m["Date"],"%Y-%m-%d").date()-today_dt).days<=7))
        q5.metric("Notes captured",       len(st.session_state.post_meeting_notes), delta="AI structured")

