                    st.markdown("#### 📐 Step 1 — Guidance & Outlook Decision Engine")
                    st.caption("CFO and CEO decide · Platform drafts language for each scenario · Louis Hoch delivers · Every word signals to the Street")

                    # ── GUIDANCE MATH ENGINE — SEASONALITY-ADJUSTED ──────────
                    # Usio has pronounced quarterly seasonality. Q2 is structurally
                    # the heaviest quarter (~35% of FY), Q3 the lightest (~18%).
                    # Equal-split H2 analysis overstates Q3 expectations by ~$7M
                    # and produces misleading guidance pace signals.
                    # Weights derived from FY2024 and FY2025 actuals (2-year avg):
                    #   Q1: 23.8% | Q2: 34.7% | Q3: 17.9% | Q4: 23.7%

                    # ── ACTUAL QUARTERLY REVENUE — SOURCE: SIX EARNINGS TRANSCRIPTS ──
                    # Q1 2025: $22.01M (confirmed, transcript header)
                    # Q2 2025: $19.90M ("down slightly"; card issuing lost ~$2M - distorted comp)
                    # Q3 2025: $21.10M (Q3 transcript: "$1.2M sequential increase" from Q2)
                    # Q4 2025: $22.24M (confirmed, transcript header)
                    # FY2025:  $85.25M (sum; consistent with "3% growth" YoY statement)
                    _q1_2025_rev = 22.01
                    _q2_2025_rev = 19.90   # Distorted low — amusement park card issuing loss
                    _q3_2025_rev = 21.10   # Derived from sequential increase disclosed
                    _q4_2025_rev = 22.24
                    _fy_2025_rev = _q1_2025_rev + _q2_2025_rev + _q3_2025_rev + _q4_2025_rev

                    # Seasonal weights — each quarter as % of actual FY2025
                    # Q2 weight (23.3%) is artificially depressed — flag throughout
                    _SEA_Q1 = _q1_2025_rev / _fy_2025_rev  # 25.8%
                    _SEA_Q2 = _q2_2025_rev / _fy_2025_rev  # 23.3% (distorted — normalized ~25.7%)
                    _SEA_Q3 = _q3_2025_rev / _fy_2025_rev  # 24.8% (seasonally softest)
                    _SEA_Q4 = _q4_2025_rev / _fy_2025_rev  # 26.1% (year-end strongest)

                    _q2_distortion_note = (
                        f"Q2 2025 (${_q2_2025_rev:.2f}M) was depressed ~$2M by the amusement park "
                        f"card issuing loss. Normalized Q2 2025 ~$21.9M. "
                        f"Q2 2026 YoY comp will appear inflated — acknowledge the easy comp in script."
                    )

                    # FY2026 guidance — 10%-12% on $85.25M FY2025 base
                    _fy_rev_base   = _fy_2025_rev
                    _fy_low_rev    = _fy_rev_base * 1.10   # $93.78M
                    _fy_hi_rev     = _fy_rev_base * 1.12   # $95.48M
                    _fy_mid_rev    = (_fy_low_rev + _fy_hi_rev) / 2  # $94.63M

                    # YTD actuals
                    _ytd_rev       = _Q1_REV + _rev   # Q1 2026 + Q2 2026

                    # Seasonal implied targets — what each remaining quarter SHOULD
                    # produce at the guidance midpoint, given historical weights
                    _q3_target_mid = _fy_mid_rev * _SEA_Q3   # ~$18.3M at midpoint
                    _q4_target_mid = _fy_mid_rev * _SEA_Q4   # ~$24.1M at midpoint
                    _q3_target_low = _fy_low_rev * _SEA_Q3   # ~$18.1M at low end
                    _q4_target_low = _fy_low_rev * _SEA_Q4   # ~$23.9M at low end

                    # Prior year actuals for the same quarters (growth benchmark)
                    _q3_yoy_needed = ((_q3_target_low / _q3_2025_rev) - 1) * 100
                    _q4_yoy_needed = ((_q4_target_low / _q4_2025_rev) - 1) * 100

                    # H2 totals
                    _h2_needed_low  = _fy_low_rev - _ytd_rev
                    _h2_needed_hi   = _fy_hi_rev  - _ytd_rev
                    _h2_2025_rev    = _q3_2025_rev + _q4_2025_rev   # $38.44M
                    _h2_growth_needed = ((_h2_needed_low / _h2_2025_rev) - 1) * 100

                    # Pace analysis — YTD as % of full-year targets
                    _ytd_pct_of_mid  = (_ytd_rev / _fy_mid_rev) * 100
                    _ytd_pct_of_low  = (_ytd_rev / _fy_low_rev) * 100
                    # Expected YTD pace through Q2 based on seasonality (Q1+Q2 weights)
                    _expected_h1_pct = (_SEA_Q1 + _SEA_Q2) * 100   # ~58.5% of FY
                    _pace_vs_seasonal = _ytd_pct_of_mid - _expected_h1_pct  # positive = running hot

                    # FY implied from H1 alone (using seasonal weight of H1)
                    _h1_weight       = _SEA_Q1 + _SEA_Q2
                    _fy_implied_h1   = _ytd_rev / _h1_weight

                    # Scenario engine — seasonality-adjusted thresholds
                    # Key insight: after Q2 (the heaviest seasonal quarter at ~35%),
                    # H1 should represent ~58.5% of FY revenue. Being above or below
                    # THAT seasonal benchmark — not a naive 50% — is the correct signal.
                    if _pace_vs_seasonal >= 3.0 and _beat_vs_street >= 1.0:
                        _guidance_scenario = "RAISE_MID"
                        _scenario_color    = "#4ADE80"
                        _scenario_bg       = "rgba(74,222,128,.08)"
                        _scenario_label    = "RAISE MIDPOINT — Running materially above seasonal pace; beat supports full range shift"
                    elif _pace_vs_seasonal >= 1.0 and _beat_vs_street >= 0:
                        _guidance_scenario = "RAISE_LOW"
                        _scenario_color    = "#60A5FA"
                        _scenario_bg       = "rgba(96,165,250,.08)"
                        _scenario_label    = "RAISE LOW END — Above seasonal pace; bank the beat into the floor"
                    elif _pace_vs_seasonal >= -1.0 and _beat_vs_street >= -0.5:
                        _guidance_scenario = "REITERATE"
                        _scenario_color    = "#FCD34D"
                        _scenario_bg       = "rgba(252,211,77,.08)"
                        _scenario_label    = "REITERATE — On seasonal pace; H2 catalysts needed before raising"
                    else:
                        _guidance_scenario = "REITERATE_CAUTIOUS"
                        _scenario_color    = "#F87171"
                        _scenario_bg       = "rgba(248,113,113,.08)"
