    def risk_level(h):
        cov = h["models_in"] / h["models_total"]
        rev_var = (h["street_rev"]-h["guidance_rev"])/h["guidance_rev"]*100 if h["guidance_rev"] else 0
        if cov == 0:           return "red",   "🔴 No data yet"
        if cov < 0.5:          return "red",   "🔴 Problem"
        if abs(rev_var) > 5:   return "red",   "🔴 Beat/miss bar too wide"
        if cov < 0.8:          return "amber", "⚠️ Watch"
        if abs(rev_var) <= 3:  return "green", "✅ In line"
        return "amber", "⚠️ Watch"

    def var_badge(street, guidance, is_eps=False):
        """Red on >2% deviation in EITHER direction for revenue — a beat-bar above guidance
        is just as much a risk signal as a miss below it, not an automatic green.
        For EPS at breakeven guidance, ANY non-zero street estimate is a red flag —
        that's a sign-flip (profitable vs not), not a magnitude question."""
        if is_eps and guidance == 0:
            if street == 0:
                return "<span style='background:#152A1E;color:#6BCB77;padding:2px 8px;border-radius:4px;font-size:12.5px;font-weight:600;'>● At B/E — in line</span>"
            sign = "+" if street > 0 else ""
            return f"<span style='background:#2D1212;color:#FF6B6B;padding:2px 8px;border-radius:4px;font-size:12.5px;font-weight:600;'>▲ {sign}${street:.2f} vs B/E — street pricing in {'profit' if street>0 else 'a loss'} you haven't guided to</span>"
        if guidance == 0: return ""
        pct  = round((street-guidance)/guidance*100,1)
        sign = "+" if pct>=0 else ""
        if abs(pct) > 2:
            arrow = "▲" if pct > 0 else "▼"
            return f"<span style='background:#2D1212;color:#FF6B6B;padding:2px 8px;border-radius:4px;font-size:12.5px;font-weight:600;'>{arrow} {sign}{pct}% — flag</span>"
        return f"<span style='background:#152A1E;color:#6BCB77;padding:2px 8px;border-radius:4px;font-size:12.5px;font-weight:600;'>● {sign}{pct}% in line</span>"

    border_colors = {"green":"#6BCB77","amber":"#F0A830","red":"#FF6B6B"}
    badge_styles  = {"green":"background:#152A1E;color:#6BCB77","amber":"background:#2D2210;color:#F0A830","red":"background:#2D1212;color:#FF6B6B"}
    level_colors  = {"red":("#2D1212","#FF6B6B","#5A2424"),"amber":("#2D2210","#F0A830","#5A4A1E"),"green":("#152A1E","#6BCB77","#2D5A3D"),"gray":("#1E2D42","#94A3B8","#334155")}

