        _overall_score = round(sum(_tracked_scores[i[1]] for i in _tracked_items) / len(_tracked_items)) if _tracked_items else 0
        _overall_color = "RED" if _overall_score < 40 else "ORANGE" if _overall_score < 60 else "YELLOW" if _overall_score < 80 else "GREEN"
        _oc, _obg = _risk_colors[_overall_color]

